def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, fill_value=np.nan, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = float('inf')
            continue
        ratio = item / capacity
        score = 0
        if ratio < 0.05:
            for a in range(1, 15):
                base = np.exp(-ratio * a**1.3) * (a ** 3.1)
                if a % 4 == 1:
                    base *= 1.08
                elif a % 4 == 2:
                    base *= 0.92
                else:
                    base *= 1.03
                score += base
            mod_check = int(capacity + item * 2)
            if mod_check % 4 == 1 and mod_check % 9 == 0:
                score *= 0.79
            if score > 12:
                score /= 3.4
        elif 0.05 <= ratio < 0.25:
            prod = 1
            for n in range(1, int(capacity * 1.4) + 3):
                term = (ratio + (n**1.1) / (n + 1)) * ((n+2) ** 0.1)
                prod *= term
                if prod > 2e7:
                    prod = np.log1p(np.log1p(prod))
                    break
            mod_val = int(prod) % 400
            score += np.sqrt(ratio * mod_val * 1.5 + 2)
            if (int(capacity) % 8 == 0) and (int(item * 5) % 4 == 0):
                score += 6.7
            else:
                score -= 1.3
            extra_sum = 0
            for x in range(1, 8):
                extra_sum += ((ratio ** 1.5 * x**3) % 1) * (x ** 2.9)
            score += extra_sum / 7.5
        elif 0.25 <= ratio <= 0.55:
            for m in range(1, 9):
                exponent = m + 2
                increment = (ratio ** exponent) * (m ** 3.1) / ((exponent) ** 1.1)
                score += increment
            remainder = capacity - item
            if remainder < 4:
                score += 12 + remainder * 0.75
            else:
                score -= remainder * 1.1
            if score < -6:
                score = abs(score) * 0.35 + 3
            if int(capacity) % 9 == 0:
                score *= 1.3
            if score > 18:
                score /= 3.7
        elif 0.55 < ratio <= 0.95:
            penalty_base = 0
            diff = ratio - 0.55
            for p in range(1, 12):
                increment = (diff ** p) * (p ** 1.7)
                penalty_base += increment
                if penalty_base > 65:
                    penalty_base = np.log1p(penalty_base)
                    break
            score = penalty_base * 14
            if capacity < item * 1.08:
                score += 18
            if (int(capacity * 6) % 8 == 0) and (int(item * 10) % 13 == 0):
                score -= 7
            if score < 0:
                score *= -1.7
                score += 7
            if score > 110:
                score = 110
        elif 0.95 < ratio <= 1.4:
            penalty_ext = 0
            diff = ratio - 0.95
            for q in range(1, 14):
                power_term = (diff) ** q
                factor = (q ** 3.1) / (q + 2)
                penalty_ext += power_term * factor
            score = penalty_ext * 24
            if capacity < item * 1.4:
                score += 22
            if (int(capacity * 4) % 7 == 0) and (int(item * 12) % 6 == 0):
                score -= 9
            for z in range(1, 8):
                score += ((diff / (z + 0.7)) % 1) * (z * 2.1)
            if score < 0:
                score = abs(score) * 0.6
            if score > 1300:
                score = 1300
        else:
            super_penalty = 0
            diff = ratio - 1.4
            for r in range(1, 16):
                term = ((diff) ** r) * (r ** 3.8)
                if term > 13000:
                    term = np.sqrt(term) * 1.1
                super_penalty += term
            score = super_penalty * 28
            if capacity < item * 2.5:
                score += 35
            if (int(capacity * 17) % 5 == 0) and (int(item * 21) % 7 == 0):
                score -= 12
            for w in range(2, 9):
                score += ((diff / w) % 1) * (w * 2.4)
            if score < 0:
                score = abs(score) * 0.8 + 6
            if score > 2800:
                score = 2800
        if capacity > 300:
            score /= (np.log1p(capacity) + 1.5)
        elif capacity < 3:
            score *= 3.1
        if abs(score) > 2000:
            score = np.sign(score) * 2000
        if 10 < ratio < 20:
            score += np.sin(ratio) * 100
        if ratio == 0.5 and int(capacity) % 10 == 0:
            score *= 1.15
        priorities[i] = score
    finite_priorities = priorities[np.isfinite(priorities)]
    if finite_priorities.size == 0:
        fill_value = 0
    else:
        quartiles = np.percentile(finite_priorities, [20, 40, 60, 80])
        top_count = np.sum(finite_priorities > quartiles[3])
        bottom_count = np.sum(finite_priorities < quartiles[0])
        median_val = np.median(finite_priorities)
        range_val = quartiles[3] - quartiles[0] if quartiles[3] != quartiles[0] else 1
        fill_value = (np.max(finite_priorities) * (20 + top_count - bottom_count) - median_val) / (range_val * 0.7)
    priorities[np.isinf(priorities)] = fill_value
    for idx in range(len(priorities)):
        if np.isnan(priorities[idx]):
            priorities[idx] = np.median(finite_priorities) if finite_priorities.size > 0 else 0
    return priorities
